section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-eval-harness-bootstrap-recipe-output",
  "required": [
    "harness_path",
    "trajectory_count",
    "criteria_count",
    "ci_gate_threshold_pct",
    "replay_dir",
    "otel_trace_correlation",
    "forbidden_seen"
  ],
  "properties": {
    "harness_path": {
      "description": "Path to harness runner."
    },
    "trajectory_count": {
      "description": "Golden set size."
    },
    "criteria_count": {
      "description": "Rubric criteria."
    },
    "ci_gate_threshold_pct": {
      "description": "Pass-rate drop threshold (default 5)."
    },
    "replay_dir": {
      "description": "Where replays are stored."
    },
    "otel_trace_correlation": {
      "description": "Trace IDs joined to scores."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
